import numpy as np

class Solver:
    def solve(self, problem, **kwargs):
        vec1, vec2 = problem
        a = np.asarray(vec1, dtype=np.float64).reshape(-1, 1)
        b = np.asarray(vec2, dtype=np.float64).reshape(1, -1)
        return np.multiply(a, b)
